        sem_post(&full);
        sem_getvalue(&empty, &val_e);
        sem_getvalue(&full, &val_f);
        printf("Produced: empty=%d full=%d\n", val_e, val_f);
    }

    for (int i = 0; i < 2; i++) {
        sem_wait(&full);
        int item = buf[cons_idx++ % N];
        sem_post(&empty);
        printf("Consumed: item=%d\n", item);
    }

    sem_destroy(&empty);
    sem_destroy(&full);
    return 0;
}

