#include <stdio.h>
#include <semaphore.h>

/* == EXEMPLE ===============================================
 * Semaphore simple : init a 2, puis attendre 2 fois
 * Pattern different du producteur-consommateur.
 * ========================================================= */
int example_simple_sem(void) {
    sem_t s;
    sem_init(&s, 0, 2);
    int v;
    sem_getvalue(&s, &v);
    printf("Initial: %d\n", v);
    sem_wait(&s);
    sem_wait(&s);
    sem_getvalue(&s, &v);
    printf("After 2 waits: %d\n", v);
    sem_post(&s);
    sem_getvalue(&s, &v);
    printf("After 1 post: %d\n", v);
    sem_destroy(&s);
    return 0;
}
/* Resultat: Initial: 2, After 2 waits: 0, After 1 post: 1 */

